+        let plan = DegradationPolicy::new(0, 0).plan(&[slice(
+            "fanout",
+            compiled.service_class,
+            compiled.delivery_policy.default_class,
+        )]);
+        assert_eq!(plan.degraded.len(), 1);
+        assert_eq!(
